#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);

my $query = CGI->new;
print $query->header('text/html');

my $log_dir = '/var/log';
my $filename = $query->param('logfile') || '';

open(FH, '<', "$log_dir/$filename") or die "Cannot open file: $!";
print "<html><body><pre>\n";
while(<FH>) {
    print;
}
close(FH);
print "</pre></body></html>\n";